import { describe, it, expect, beforeEach } from 'vitest';
import { DarkSectorVault } from './dark-atomized-encryption';
import { createEngine, MeshEngine } from './mesh-engine';
import { DisjointDarkMatterFork } from './dark-fork-topology';
import { dnaToKnot, knotToDna } from './runtime/packed-knot';

describe('Dark Sector Atomized Encryption (DSAE)', () => {
  let engine: MeshEngine;
  let vault_manager: DarkSectorVault;
  let darkMatter: DisjointDarkMatterFork;

  beforeEach(() => {
    engine = createEngine('proton', 3);
    vault_manager = new DarkSectorVault(engine);
    darkMatter = new DisjointDarkMatterFork(engine);
  });

  it('should be invisible to Gauge Observation (Race) but reconstructible via Gravity Fold', async () => {
    const dnaSecret = "ACGTACGT";
    const secretKnot = dnaToKnot(dnaSecret);
    const vault = await vault_manager.encrypt(secretKnot, 2, {
      uncertainty: 0.8,
      complexity: 0.5,
      novelty: 0.9,
      budgetSlack: 0.1
    });

    // 1. Attempt decryption via Race (The "Quick" Observer)
    const raceResult = await darkMatter.gaugeRace(vault.shards);
    expect(raceResult).toBeNull(); // Invisible to electromagnetic/gauge observation

    // 2. Decrypt via Gravity Fold (The "Global" Observer)
    const resultKnot = await vault_manager.decrypt(vault);
    
    expect(knotToDna(resultKnot)).toBe(dnaSecret);

    // Cleanup expansion
    vault.expansion.stop();
  });

  it('should leverage Dark Energy to expand the mesh fabric during encryption', async () => {
    const secretKnot = dnaToKnot("A");
    // Highly stressed signals = high rev = small expansionDelay = more expansion
    const vault = await vault_manager.encrypt(secretKnot, 1, {
      uncertainty: 0.9,
      complexity: 0.9,
      novelty: 0.9,
      budgetSlack: 0.1
    });

    // Wait longer for some dark energy expansion to happen
    await new Promise(r => setTimeout(r, 100));
    
    // @ts-expect-error -- accessing private for test verification
    const expansion = vault.expansion.fabricDimensionExpansion;
    expect(expansion).toBeGreaterThan(0);

    vault.expansion.stop();
  });
});
